#!/usr/bin/env node
// Authoring tool (run once when the selection changes): reads the curated
// selection input and freezes EXPLICIT LITERAL tokenIds (rpt-0037+) into
// data/v2-metadata.mjs. The generated file — not this script and not the
// input — is the committed source of truth the build reads. tokenIds live in
// that file as literal strings and are never derived at runtime.
import { writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { V2_NEW_SELECTIONS } from "./data/v2-selection-input.mjs";

const here = path.dirname(fileURLToPath(import.meta.url));
const outPath = path.join(here, "data", "v2-metadata.mjs");

const FIRST_NEW_ID = 37; // rpt-0001..rpt-0036 are the frozen V1 ids.

function tokenIdFor(index) {
  return `rpt-${String(FIRST_NEW_ID + index).padStart(4, "0")}`;
}

function serializeEntry(e, tokenId) {
  const parts = [
    `tokenId: ${JSON.stringify(tokenId)}`,
    `id: ${JSON.stringify(e.id)}`,
    `name: ${JSON.stringify(e.name)}`,
    `symbol: ${JSON.stringify(e.symbol)}`,
    `slug: ${JSON.stringify(e.slug)}`,
    `category: ${JSON.stringify(e.category)}`,
    `assetClass: ${JSON.stringify(e.assetClass)}`,
    `eligibilityTier: ${JSON.stringify(e.tier)}`,
    `aliases: ${JSON.stringify(e.aliases ?? [])}`,
  ];
  if (e.symbolConflictGroup) parts.push(`symbolConflictGroup: ${JSON.stringify(e.symbolConflictGroup)}`);
  return `  { ${parts.join(", ")} },`;
}

function main() {
  const lines = V2_NEW_SELECTIONS.map((e, i) => serializeEntry(e, tokenIdFor(i)));
  const header = `// GENERATED by tools/registry/gen-v2-metadata.mjs from
// data/v2-selection-input.mjs. Do not hand-edit: change the input then
// re-run \`node tools/registry/gen-v2-metadata.mjs\`.
//
// This is the committed source of truth for the 214 NEW V2 proposal entries.
// Every tokenId below is an EXPLICIT LITERAL string (rpt-0037..rpt-0250) — the
// build reads these literals and never derives a tokenId from array position.
// The 36 frozen V1 entries (rpt-0001..rpt-0036) are NOT listed here; the build
// preserves them verbatim from registry/tokens/v1/registry.json.
export const V2_NEW_ENTRIES = [
`;
  writeFileSync(outPath, `${header}${lines.join("\n")}\n];\n`, "utf8");
  console.log(`Wrote ${outPath} with ${V2_NEW_SELECTIONS.length} entries (${tokenIdFor(0)}..${tokenIdFor(V2_NEW_SELECTIONS.length - 1)}).`);
}

main();
